class SecureKafkaProducerService {
    private final KafkaTemplate<String, String> kafkaTemplate;

    public SecureKafkaProducerService(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public ProducerResult sendMessage(EventMessage message) {
        MessageValidator.ValidationResult messageValidation = MessageValidator.validate(message);
        if (!messageValidation.isValid()) {
            return new ProducerResult(false, messageValidation.getErrorMessage(), null);
        }

        HeaderValidator.ValidationResult headerValidation = HeaderValidator.validate(message.getHeaders());
        if (!headerValidation.isValid()) {
            return new ProducerResult(false, headerValidation.getErrorMessage(), null);
        }

        try {
            ProducerRecord<String, String> record = createProducerRecord(message);
            RecordMetadata metadata = kafkaTemplate.send(record).get().getRecordMetadata();
            
            return new ProducerResult(true, "Message sent successfully", 
                new MessageMetadata(metadata.topic(), metadata.partition(), metadata.offset()));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return new ProducerResult(false, "Message sending interrupted", null);
        } catch (ExecutionException e) {
            return new ProducerResult(false, "Failed to send message: " + e.getCause().getMessage(), null);
        } catch (Exception e) {
            return new ProducerResult(false, "Unexpected error: " + e.getMessage(), null);
        }
    }

    private ProducerRecord<String, String> createProducerRecord(EventMessage message) {
        List<Header> headers = new ArrayList<>();
        
        if (message.getHeaders() != null) {
            for (Map.Entry<String, String> entry : message.getHeaders().entrySet()) {
                String sanitizedKey = sanitizeHeaderKey(entry.getKey());
                String sanitizedValue = sanitizeHeaderValue(entry.getValue());
                headers.add(new RecordHeader(sanitizedKey, 
                    sanitizedValue.getBytes(StandardCharsets.UTF_8)));
            }
        }

        headers.add(new RecordHeader("producer-timestamp", 
            String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8)));
        headers.add(new RecordHeader("producer-version", 
            "1.0.0".getBytes(StandardCharsets.UTF_8)));

        return new ProducerRecord<>(
            message.getTopic(),
            null,
            message.getKey(),
            message.getPayload(),
            headers
        );
    }

    private String sanitizeHeaderKey(String key) {
        if (key == null) {
            return "";
        }
        return key.trim().toLowerCase();
    }

    private String sanitizeHeaderValue(String value) {
        if (value == null) {
            return "";
        }
        return value.trim();
    }

    static class ProducerResult {
        private final boolean success;
        private final String message;
        private final MessageMetadata metadata;

        public ProducerResult(boolean success, String message, MessageMetadata metadata) {
            this.success = success;
            this.message = message;
            this.metadata = metadata;
        }

        public boolean isSuccess() {
            return success;
        }

        public String getMessage() {
            return message;
        }

        public MessageMetadata getMetadata() {
            return metadata;
        }
    }

    static class MessageMetadata {
        private final String topic;
        private final int partition;
        private final long offset;

        public MessageMetadata(String topic, int partition, long offset) {
            this.topic = topic;
            this.partition = partition;
            this.offset = offset;
        }

        public String getTopic() {
            return topic;
        }

        public int getPartition() {
            return partition;
        }

        public long getOffset() {
            return offset;
        }
    }
}

@RestController
@RequestMapping("/api/events")
class EventProducerController {
    private final SecureKafkaProducerService producerService;

    public EventProducerController(KafkaTemplate<String, String> kafkaTemplate) {
        this.producerService = new SecureKafkaProducerService(kafkaTemplate);
    }

    @PostMapping("/publish")
    public ResponseEntity<Map<String, Object>> publishEvent(@RequestBody EventMessage message) {
        SecureKafkaProducerService.ProducerResult result = producerService.sendMessage(message);
        
        Map<String, Object> response = new HashMap<>();
        response.put("success", result.isSuccess());
        response.put("message", result.getMessage());
        
        if (result.getMetadata() != null) {
            Map<String, Object> metadata = new HashMap<>();
            metadata.put("topic", result.getMetadata().getTopic());
            metadata.put("partition", result.getMetadata().getPartition());
            metadata.put("offset", result.getMetadata().getOffset());
            response.put("metadata", metadata);
        }

        HttpStatus status = result.isSuccess() ? HttpStatus.OK : HttpStatus.BAD_REQUEST;
        return new ResponseEntity<>(response, status);
    }

    @PostMapping("/batch")
    public ResponseEntity<Map<String, Object>> publishBatch(@RequestBody List<EventMessage> messages) {
        if (messages == null || messages.isEmpty()) {
            Map<String, Object> response = new HashMap<>();
            response.put("success", false);
            response.put("message", "Message list cannot be empty");
            return new ResponseEntity<>(response, HttpStatus.BAD_REQUEST);
        }

        if (messages.size() > 100) {
            Map<String, Object> response = new HashMap<>();
            response.put("success", false);
            response.put("message", "Batch size exceeds maximum allowed (100)");
            return new ResponseEntity<>(response, HttpStatus.BAD_REQUEST);
        }

        List<Map<String, Object>> results = new ArrayList<>();
        int successCount = 0;
        int failureCount = 0;

        for (EventMessage message : messages) {
            SecureKafkaProducerService.ProducerResult result = producerService.sendMessage(message);
            
            Map<String, Object> resultMap = new HashMap<>();
            resultMap.put("success", result.isSuccess());
            resultMap.put("message", result.getMessage());
            
            if (result.getMetadata() != null) {
                Map<String, Object> metadata = new HashMap<>();
                metadata.put("topic", result.getMetadata().getTopic());
                metadata.put("partition", result.getMetadata().getPartition());
                metadata.put("offset", result.getMetadata().getOffset());
                resultMap.put("metadata", metadata);
            }
            
            results.add(resultMap);
            
            if (result.isSuccess()) {
                successCount++;
            } else {
                failureCount++;
            }
        }

        Map<String, Object> response = new HashMap<>();
        response.put("totalMessages", messages.size());
        response.put("successCount", successCount);
        response.put("failureCount", failureCount);
        response.put("results", results);

        return new ResponseEntity<>(response, HttpStatus.OK);
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> health() {
        Map<String, String> response = new HashMap<>();
        response.put("status", "UP");
        response.put("service", "Kafka Event Producer");
        return ResponseEntity.ok(response);
    }
}